def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        for j in range(n - i - 1):  # Changed range to n - i - 1
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

def calculate_average(numbers):
    if len(numbers) == 0:  # Added check for empty list
        return 0  # or any other default value
    total = 0
    for num in numbers:
        total += num
    return total / len(numbers)

print(bubble_sort([64, 34, 25, 12]))
print(calculate_average([]))
